 31→fn position_near_top(window: &tauri::WebviewWindow) {
 32→    let monitor = window
 33→        .current_monitor()
 34→        .ok()
 35→        .flatten()
 36→        .or_else(|| window.primary_monitor().ok().flatten());
 37→
 38→    if let Some(monitor) = monitor {
 39→        let monitor_size = monitor.size();
 40→        let monitor_pos = monitor.position();
 41→
 42→        if let Ok(window_size) = window.outer_size() {
 43→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 44→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 45→
 46→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 47→                eprintln!("failed to position window: {e}");
 48→            }
 49→        }
 50→    } else if let Err(e) = window.center() {
 51→        eprintln!("failed to center window: {e}");
 52→    }
 53→}
