 93→fn detect_content_type(content: &str) -> &'static str {
 94→    let trimmed = content.trim();
 95→
 96→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
 97→        return "link";
 98→    }
 99→
100→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
101→        && trimmed.starts_with('#')
102→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
103→    {
104→        return "color";
105→    }
106→
107→    if trimmed.starts_with("rgb(")
108→        || trimmed.starts_with("rgba(")
109→        || trimmed.starts_with("hsl(")
110→        || trimmed.starts_with("hsla(")
111→    {
112→        return "color";
113→    }
114→
115→    "text"
116→}
