169→fn detect_file_type(path: &std::path::Path) -> &'static str {
170→    if path.is_dir() {
171→        return "folder";
172→    }
173→
174→    match path
175→        .extension()
176→        .and_then(|e| e.to_str())
177→        .map(|e| e.to_lowercase())
178→        .as_deref()
179→    {
180→        Some(
181→            "ts" | "tsx" | "js" | "jsx" | "rs" | "py" | "rb" | "go" | "java" | "c" | "cpp" | "h"
182→            | "hpp" | "cs" | "swift" | "kt" | "scala" | "sh" | "bash" | "zsh" | "json" | "yaml"
183→            | "yml" | "toml" | "xml" | "html" | "css" | "scss" | "less" | "sql" | "graphql"
184→            | "proto" | "lua" | "r" | "php" | "pl" | "ex" | "exs" | "erl" | "hs" | "ml"
185→            | "vim" | "el" | "clj" | "dart",
186→        ) => "code",
187→        Some("png" | "jpg" | "jpeg" | "gif" | "bmp" | "svg" | "webp" | "ico" | "tiff" | "avif") => {
188→            "image"
189→        }
190→        Some("pdf") => "pdf",
191→        Some("zip" | "tar" | "gz" | "bz2" | "xz" | "7z" | "rar" | "dmg" | "iso") => "archive",
192→        Some("xlsx" | "xls" | "csv" | "numbers" | "ods") => "spreadsheet",
193→        Some("pptx" | "ppt" | "key" | "odp") => "presentation",
194→        Some(
195→            "md" | "txt" | "rtf" | "doc" | "docx" | "pages" | "odt" | "tex" | "log" | "conf"
196→            | "cfg" | "ini" | "env" | "fig",
197→        ) => "document",
198→        _ => "document",
199→    }
200→}
