406→fn scan_app_dir(dir: &std::path::Path, depth: usize) -> Vec<std::path::PathBuf> {
407→    let mut apps = Vec::new();
408→    let Ok(entries) = std::fs::read_dir(dir) else {
409→        return apps;
410→    };
411→
412→    for entry in entries.flatten() {
413→        let path = entry.path();
414→        if path.extension().map_or(false, |e| e == "app") {
415→            apps.push(path);
416→        } else if depth > 0 && path.is_dir() {
417→            let name = path.file_name().unwrap_or_default().to_string_lossy();
418→            if !name.starts_with('.') {
419→                apps.extend(scan_app_dir(&path, depth - 1));
420→            }
421→        }
422→    }
423→    apps
424→}
