426→fn read_app_display_name(app_path: &std::path::Path) -> Option<String> {
427→    let info_plist = app_path.join("Contents/Info.plist");
428→    let dict: plist::Dictionary = plist::from_file(info_plist).ok()?;
429→
430→    dict.get("CFBundleDisplayName")
431→        .or_else(|| dict.get("CFBundleName"))
432→        .and_then(|v| v.as_string())
433→        .map(|s| s.to_string())
434→}
