436→fn extract_png_from_icns(icns_data: &[u8]) -> Option<Vec<u8>> {
437→    if icns_data.len() < 8 || &icns_data[0..4] != b"icns" {
438→        return None;
439→    }
440→
441→    let total_len = u32::from_be_bytes(icns_data[4..8].try_into().ok()?) as usize;
442→    let total_len = total_len.min(icns_data.len());
443→
444→    let preferred: &[&[u8; 4]] = &[
445→        b"icp6", b"icp5", b"ic07", b"icp4", b"ic08", b"ic09", b"ic10",
446→    ];
447→
448→    let mut offset = 8;
449→    let mut entries: Vec<(&[u8], &[u8])> = Vec::new();
450→
451→    while offset + 8 <= total_len {
452→        let type_code = &icns_data[offset..offset + 4];
453→        let entry_len = u32::from_be_bytes(icns_data[offset + 4..offset + 8].try_into().ok()?) as usize;
454→        if entry_len < 8 || offset + entry_len > total_len {
455→            break;
456→        }
457→        let data = &icns_data[offset + 8..offset + entry_len];
458→        entries.push((type_code, data));
459→        offset += entry_len;
460→    }
461→
462→    for pref in preferred {
463→        for (type_code, data) in &entries {
464→            if *type_code == pref.as_slice() && data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
465→                return Some(data.to_vec());
466→            }
467→        }
468→    }
469→
470→    for (_, data) in &entries {
471→        if data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
472→            return Some(data.to_vec());
473→        }
474→    }
475→
476→    None
477→}
478→
479→fn extract_app_icon(app_path: &std::path::Path) -> Option<String> {
480→    let info_plist = app_path.join("Contents/Info.plist");
481→    let dict: plist::Dictionary = plist::from_file(info_plist).ok()?;
482→
483→    let icon_name = dict
484→        .get("CFBundleIconFile")
485→        .and_then(|v| v.as_string())
486→        .unwrap_or("AppIcon");
487→
488→    let icon_filename = if icon_name.ends_with(".icns") {
489→        icon_name.to_string()
490→    } else {
491→        format!("{icon_name}.icns")
492→    };
493→
494→    let icns_path = app_path.join("Contents/Resources").join(&icon_filename);
495→    let icns_data = std::fs::read(&icns_path).ok()?;
496→    let png_data = extract_png_from_icns(&icns_data)?;
497→
498→    Some(format!(
499→        "data:image/png;base64,{}",
500→        base64::engine::general_purpose::STANDARD.encode(&png_data)
501→    ))
502→}
