504→fn build_app_list() -> Vec<AppEntry> {
505→    let mut apps = Vec::new();
506→    let mut seen_paths = std::collections::HashSet::new();
507→
508→    let mut dirs = vec![std::path::PathBuf::from("/Applications")];
509→    if let Some(home) = dirs_next::home_dir() {
510→        dirs.push(home.join("Applications"));
511→    }
512→
513→    for dir in &dirs {
514→        for app_path in scan_app_dir(dir, 1) {
515→            let path_str = app_path.to_string_lossy().to_string();
516→            if !seen_paths.insert(path_str.clone()) {
517→                continue;
518→            }
519→
520→            let file_stem = app_path
521→                .file_stem()
522→                .map(|s| s.to_string_lossy().to_string())
523→                .unwrap_or_default();
524→
525→            let name = read_app_display_name(&app_path).unwrap_or_else(|| file_stem.clone());
526→            let icon = extract_app_icon(&app_path);
527→
528→            let id = format!("app-{:x}", {
529→                use std::hash::{Hash, Hasher};
530→                let mut h = std::collections::hash_map::DefaultHasher::new();
531→                path_str.hash(&mut h);
532→                h.finish()
533→            });
534→
535→            apps.push(AppEntry {
536→                id,
537→                name,
538→                path: path_str,
539→                icon,
540→            });
541→        }
542→    }
543→
544→    apps.sort_by(|a, b| a.name.to_lowercase().cmp(&b.name.to_lowercase()));
545→    apps
546→}
