548→#[tauri::command(async)]
549→fn discover_applications(
550→    state: tauri::State<'_, Mutex<AppCache>>,
551→    force_refresh: bool,
552→) -> Vec<AppEntry> {
553→    if !force_refresh {
554→        if let Ok(cache) = state.lock() {
555→            if let Some(ref apps) = cache.apps {
556→                return apps.clone();
557→            }
558→        }
559→    }
560→
561→    let apps = build_app_list();
562→
563→    if let Ok(mut cache) = state.lock() {
564→        cache.apps = Some(apps.clone());
565→    }
566→
567→    apps
568→}
