614→#[cfg_attr(mobile, tauri::mobile_entry_point)]
615→pub fn run() {
616→    tauri::Builder::default()
617→        .plugin(tauri_plugin_clipboard_manager::init())
618→        .plugin(tauri_plugin_shell::init())
619→        .manage(Mutex::new(WindowConfig::default()))
620→        .manage(Mutex::new(AppCache::default()))
621→        .invoke_handler(tauri::generate_handler![
622→            set_window_position_pref,
623→            search_files,
624→            open_file,
625→            reveal_in_finder,
626→            move_to_trash,
627→            discover_applications,
628→            launch_application
629→        ])
630→        .setup(|app| {
631→            #[cfg(desktop)]
632→            {
633→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
634→                let window = app
635→                    .get_webview_window("main")
636→                    .expect("main window not found");
637→
638→                let window_for_blur = window.clone();
