 1→import { useCallback, useEffect, useRef, useState } from 'react';
 2→import type { AppEntry } from '../platform';
 3→import { getPlatform, isTauri } from '../platform';
 4→
 5→interface UseApplicationsResult {
 6→  applications: AppEntry[];
 7→  refresh: () => void;
 8→}
 9→
10→export function useApplications(): UseApplicationsResult {
11→  const [applications, setApplications] = useState<AppEntry[]>([]);
12→  const loadedRef = useRef(false);
13→
14→  const loadApps = useCallback((forceRefresh: boolean) => {
15→    if (!isTauri) return;
16→    getPlatform()
17→      .apps.discoverApplications(forceRefresh)
18→      .then(setApplications)
19→      .catch(() => {});
20→  }, []);
21→
22→  useEffect(() => {
23→    if (loadedRef.current) return;
