use std::sync::Mutex;
use std::time::Duration;
use base64::Engine;
use serde::Serialize;
use tauri::{Emitter, Manager};
use walkdir::WalkDir;
#[cfg(desktop)]
use tauri::menu::{Menu, MenuItem, PredefinedMenuItem};
#[cfg(desktop)]
use tauri::tray::{MouseButton, MouseButtonState, TrayIconBuilder, TrayIconEvent};
#[cfg(desktop)]
